import React, { useState, useEffect, useRef } from 'react';
import { devicesApi } from '../lib/api';

const Terminal = () => {
  const [tabs, setTabs] = useState([]);
  const [activeTab, setActiveTab] = useState(null);
  const [devices, setDevices] = useState([]);
  const [showDeviceList, setShowDeviceList] = useState(false);

  const wsRef = useRef(null);
  const inputRef = useRef(null);
  const terminalRef = useRef(null);

  useEffect(() => { loadDevices(); }, []);

  const loadDevices = async () => {
    try {
      const res = await devicesApi.list();
      setDevices(res || []);
    } catch (e) { console.error(e); }
  };

  const openNewTab = (device) => {
    const existing = tabs.find(t => t.deviceId === device.id);
    if (existing) { setActiveTab(existing.id); setShowDeviceList(false); return; }

    const tabId = Date.now();
    const tab = {
      id: tabId,
      deviceId: device.id,
      name: device.hostname,
      ip: device.ip_address,
      port: device.port || 22,
      user: device.username || 'root',
      vendor: device.vendor || '',
      output: [],
      connected: false,
      ws: null
    };

    setTabs(prev => [...prev, tab]);
    setActiveTab(tabId);
    setShowDeviceList(false);

    // Conectar via WebSocket
    connectSSH(tabId, device);
  };

  const connectSSH = (tabId, device) => {
    try {
      const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
      const wsUrl = `${protocol}//${window.location.host}/ws/ssh/`;

      const ws = new WebSocket(wsUrl);

      ws.onopen = () => {
        ws.send(JSON.stringify({
          type: 'connect',
          device_id: device.id
        }));

        setTabs(prev => prev.map(t => 
          t.id === tabId ? { ...t, ws } : t
        ));
      };

      ws.onmessage = (event) => {
        const data = JSON.parse(event.data);
        if (data.type === 'output' || data.type === 'connected') {
          setTabs(prev => prev.map(t => 
            t.id === tabId ? { 
              ...t, 
              output: [...t.output, data.data],
              connected: data.type === 'connected' ? true : t.connected
            } : t
          ));
          scrollToBottom(tabId);
        } else if (data.type === 'error') {
          setTabs(prev => prev.map(t => 
            t.id === tabId ? { 
              ...t, 
              output: [...t.output, '\x1b[31m' + data.data + '\x1b[0m'],
              connected: false
            } : t
          ));
        }
      };

      ws.onerror = () => {
        // Fallback para simulação
        startSimulation(tabId, device);
      };

      ws.onclose = () => {
        setTabs(prev => prev.map(t => 
          t.id === tabId ? { ...t, connected: false, ws: null } : t
        ));
      };

      wsRef.current = { ...wsRef.current, [tabId]: ws };

    } catch (error) {
      startSimulation(tabId, device);
    }
  };

  const startSimulation = (tabId, device) => {
    setTabs(prev => prev.map(t => 
      t.id === tabId ? { 
        ...t, 
        output: [
          '\x1b[33m[Modo Simulação - WebSocket não disponível]\x1b[0m',
          `Conectado a ${device.hostname} (${device.ip_address})`,
          'Digite "help" para comandos disponíveis',
          ''
        ],
        connected: true,
        simulated: true
      } : t
    ));
  };

  const scrollToBottom = (tabId) => {
    setTimeout(() => {
      const el = document.getElementById('term-' + tabId);
      if (el) el.scrollTop = el.scrollHeight;
    }, 10);
  };

  const sendInput = (tabId, input) => {
    const tab = tabs.find(t => t.id === tabId);
    if (!tab) return;

    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
      tab.ws.send(JSON.stringify({ type: 'input', data: input }));
    } else if (tab.simulated) {
      // Modo simulação
      handleSimulatedCommand(tabId, input);
    }
  };

  const handleSimulatedCommand = (tabId, cmd) => {
    const tab = tabs.find(t => t.id === tabId);
    if (!tab) return;

    const prompt = tab.user + '@' + tab.name + ':~$ ';
    let output = '';

    // Adicionar comando ao output
    setTabs(prev => prev.map(t => 
      t.id === tabId ? { ...t, output: [...t.output, prompt + cmd] } : t
    ));

    // Processar comando
    const cmdLower = cmd.trim().toLowerCase();
    const vendor = (tab.vendor || '').toLowerCase();

    if (vendor.includes('huawei')) {
      if (cmdLower === 'display version') output = 'Huawei VRP Version 8.231\nNE8000 V800R023C10SPC500';
      else if (cmdLower === 'display cpu') output = 'CPU utilization: 15%';
      else if (cmdLower === 'display memory') output = 'Memory: 45% used\nTotal: 8192 MB';
      else if (cmdLower === 'display interface brief') output = 'Interface        PHY   Protocol\nGE0/0/0          up    up\nGE0/0/1          up    up';
      else if (cmdLower === 'help') output = 'Comandos Huawei:\n  display version\n  display cpu\n  display memory\n  display interface brief\n  display arp\n  display ip routing-table';
      else if (cmdLower === 'exit' || cmdLower === 'quit') { closeTab(tabId); return; }
      else if (cmdLower) output = `Comando: ${cmd}`;
    } else if (vendor.includes('mikrotik')) {
      if (cmdLower === '/system resource') output = 'uptime: 5d12h\nversion: 7.10\ncpu-load: 15%';
      else if (cmdLower === '/interface print') output = ' #   NAME      TYPE\n 0 R ether1    ether\n 1 R ether2    ether';
      else if (cmdLower === '/ppp active print') output = ' #   NAME    UPTIME\n 0 R user1   2d5h\n 1 R user2   1d3h\n\nTotal: 2';
      else if (cmdLower === '/export') output = '# Mikrotik Config\n/interface bridge add name=bridge1';
      else if (cmdLower === 'help') output = 'Comandos Mikrotik:\n  /system resource\n  /interface print\n  /ppp active print\n  /export\n  /ip address print';
      else if (cmdLower === 'exit' || cmdLower === 'quit') { closeTab(tabId); return; }
      else if (cmdLower) output = `Comando: ${cmd}`;
    } else {
      // Linux
      if (cmdLower === 'ls') output = 'Documents  Downloads  scripts';
      else if (cmdLower === 'ls -la') output = 'drwxr-xr-x  5 root root 4096 .\n-rw-r--r--  1 root root  220 .bashrc';
      else if (cmdLower === 'pwd') output = '/root';
      else if (cmdLower === 'whoami') output = tab.user;
      else if (cmdLower === 'hostname') output = tab.name.toLowerCase();
      else if (cmdLower === 'date') output = new Date().toString();
      else if (cmdLower === 'uptime') output = 'up 5 days, 12:34, 1 user, load: 0.15';
      else if (cmdLower === 'free -h') output = 'Mem: 7.8Gi used 1.2Gi free 4.5Gi';
      else if (cmdLower === 'df -h') output = 'Filesystem  Size  Used Avail\n/dev/sda1   98G    19G   75G';
      else if (cmdLower === 'ip a' || cmdLower === 'ip addr') output = '1: lo: inet 127.0.0.1\n2: eth0: inet ' + tab.ip + '/24';
      else if (cmdLower === 'help') output = 'Comandos: ls, pwd, whoami, hostname, date, uptime\n  free -h, df -h, ip a, ping, ps aux\n  clear, exit';
      else if (cmdLower === 'clear') {
        setTabs(prev => prev.map(t => t.id === tabId ? { ...t, output: [] } : t));
        return;
      }
      else if (cmdLower === 'exit' || cmdLower === 'quit') { closeTab(tabId); return; }
      else if (cmdLower) output = `bash: ${cmdLower.split(' ')[0]}: command not found`;
    }

    if (output) {
      setTabs(prev => prev.map(t => 
        t.id === tabId ? { ...t, output: [...t.output, output] } : t
      ));
    }
    setTabs(prev => prev.map(t => 
      t.id === tabId ? { ...t, output: [...t.output, ''] } : t
    ));
    scrollToBottom(tabId);
  };

  const closeTab = (tabId, e) => {
    if (e) e.stopPropagation();

    const tab = tabs.find(t => t.id === tabId);
    if (tab?.ws) {
      tab.ws.close();
    }

    setTabs(prev => {
      const n = prev.filter(t => t.id !== tabId);
      if (activeTab === tabId && n.length) setActiveTab(n[n.length - 1].id);
      else if (!n.length) setActiveTab(null);
      return n;
    });
  };

  const handleKeyDown = (e, tabId) => {
    if (e.key === 'Enter') {
      sendInput(tabId, e.target.value);
      e.target.value = '';
    } else if (e.ctrlKey && e.key === 'c') {
      sendInput(tabId, '\x03');
    }
  };

  const renderOutput = (text) => {
    // Processar cores ANSI
    let html = text
      .replace(/\x1b\[31m/g, '<span class="text-red-400">')
      .replace(/\x1b\[32m/g, '<span class="text-green-400">')
      .replace(/\x1b\[33m/g, '<span class="text-yellow-400">')
      .replace(/\x1b\[36m/g, '<span class="text-cyan-400">')
      .replace(/\x1b\[0m/g, '</span>');
    return <span dangerouslySetInnerHTML={{ __html: html }} />;
  };

  const currentTab = tabs.find(t => t.id === activeTab);

  return (
    <div className="flex flex-col h-[calc(100vh-150px)] bg-black rounded-lg overflow-hidden border border-gray-700">
      {/* Tabs */}
      <div className="flex bg-gray-800 border-b border-gray-700">
        <div className="flex-1 flex overflow-x-auto">
          {tabs.map(t => (
            <div key={t.id} onClick={() => setActiveTab(t.id)}
              className={`flex items-center px-4 py-2 cursor-pointer border-r border-gray-700 ${activeTab === t.id ? 'bg-gray-900 text-white' : 'text-gray-400 hover:bg-gray-700'}`}>
              <span className={`w-2 h-2 rounded-full mr-2 ${t.connected ? 'bg-green-500' : 'bg-yellow-500'}`} />
              <span className="text-sm">{t.name}</span>
              <button onClick={(e) => closeTab(t.id, e)} className="ml-2 text-gray-500 hover:text-red-400">x</button>
            </div>
          ))}
        </div>
        <button onClick={() => setShowDeviceList(!showDeviceList)} className="px-4 py-2 text-gray-400 hover:text-white text-xl">+</button>
      </div>

      {/* Device list */}
      {showDeviceList && (
        <div className="absolute top-28 right-6 w-72 bg-gray-800 border border-gray-700 rounded-lg shadow-xl z-50 max-h-80 overflow-y-auto">
          <div className="p-3 border-b border-gray-700 text-white font-medium">Conectar a:</div>
          <div className="p-2">
            {devices.map(d => (
              <button key={d.id} onClick={() => openNewTab(d)}
                className="w-full p-3 rounded hover:bg-gray-700 text-left flex items-center">
                <span className="w-2 h-2 rounded-full bg-green-500 mr-3" />
                <div className="flex-1">
                  <div className="text-white text-sm">{d.hostname}</div>
                  <div className="text-gray-500 text-xs">{d.ip_address}:{d.port || 22}</div>
                </div>
                <span className="text-xs text-gray-500">{d.vendor}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Terminal */}
      {currentTab ? (
        <div ref={terminalRef} id={'term-' + currentTab.id}
          className="flex-1 overflow-y-auto p-3 font-mono text-sm bg-black cursor-text"
          onClick={() => inputRef.current?.focus()}>

          {currentTab.output.map((line, i) => (
            <div key={i} className="whitespace-pre-wrap text-green-400 leading-relaxed">
              {renderOutput(line)}
            </div>
          ))}

          <div className="flex">
            <span className="text-green-400">{currentTab.user}@{currentTab.name}:~$ </span>
            <input ref={inputRef} type="text"
              className="flex-1 bg-transparent outline-none text-green-400 caret-green-400"
              onKeyDown={(e) => handleKeyDown(e, currentTab.id)}
              autoFocus spellCheck="false" autoComplete="off" />
          </div>
        </div>
      ) : (
        <div className="flex-1 flex flex-col items-center justify-center text-gray-500 bg-black">
          <div className="text-5xl mb-4 font-mono">&gt;_</div>
          <div className="text-xl text-white mb-2">Terminal SSH</div>
          <div className="mb-4 text-sm">Clique + para nova conexao</div>
          <button onClick={() => setShowDeviceList(true)} className="px-6 py-2 bg-blue-600 text-white rounded">Nova Conexao</button>
        </div>
      )}

      {/* Status bar */}
      {currentTab && (
        <div className="flex justify-between px-4 py-1 bg-gray-800 border-t border-gray-700 text-xs text-gray-400">
          <span>{currentTab.ip}:{currentTab.port} | {currentTab.user}</span>
          <span className={currentTab.connected ? 'text-green-400' : 'text-yellow-400'}>
            {currentTab.connected ? '● Conectado' : '○ Conectando...'}
          </span>
        </div>
      )}
    </div>
  );
};

export default Terminal;
